class Solution(object):
    def minimumOperations(self, nums):
        # Minimum removals = n - length of longest non-decreasing subsequence
        # using only values 1, 2, 3
        # dp[v] = length of longest non-decreasing subsequence ending with value v
        dp = [0, 0, 0]  # dp[0]=ends with 1, dp[1]=ends with 2, dp[2]=ends with 3
        for x in nums:
            v = x - 1
            dp[v] = max(dp[:v + 1]) + 1
        return len(nums) - max(dp)
